var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"흠~ 흠흠~ 이제 슬슬 제 차례인가요?","JPN":"ふん～ふふん～そろそろ私の番でしょうか。","ENG":"*Humming* Is it almost my turn?","TWN":"哼哼♬～現在該輪到我了嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"무책임한 어머님과 비교하면 아직 부족하지만…….","JPN":"無責任なお母さんに比べるとまだまだ未熟ですけど……","ENG":"It isn't enough compared to my irresponsible Mother, but...","TWN":"雖然跟不負責任的母親相比，還有些不足……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"제가 깊은 잠에 빠져 있던 동안, 기사님께서 충실하게 파편을 모아주셨거든요.","JPN":"私が深い眠りについている間、騎士様が真面目に破片を集めてくださったんです。","ENG":"While I was in deep slumber, my knight worked hard to gather Fragments.","TWN":"但在我熟睡的時候，騎士忠實地替我收集了碎片。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"덕분에 수많은 우리들이 다시 하나가 될 수 있었답니다.","JPN":"おかげで大勢の我々は再び一つになることができました。","ENG":"And so our countless selves were able to become one again.","TWN":"托你的福，無數的我們才能重新合而為一。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그러니까 이제 당신도 파편을 전부 제게 넘기고 하나가 되는 거예요.","JPN":"ですからあなたも破片をすべて私に渡して、一つになるのです。","ENG":"So you should hand over all your Fragments to me and become one with us.","TWN":"所以，把你的碎片也交給我，然後合而為一吧。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"……이브.","JPN":"……イヴ。","ENG":"...Eve.","TWN":"……伊芙。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"네가 누군지는 모르겠지만, 내 안의 파편은 아무한테도 안 넘길 거야.","JPN":"あなたが誰だかは知らないけど、私の中の破片は誰にも渡さない。","ENG":"I don't know who you are, but I'm not giving away the Fragment inside of me to anyone.","TWN":"雖然不知道你是誰，但是我不會把我的碎片交給任何人。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아무리 힘들고, 고통스러워도…… 언제까지나 꼭 참아내기로.","JPN":"どんなに辛くても苦しくても……いつまでも我慢するわ。","ENG":"I will endure... no matter how tiring or painful it is.","TWN":"無論多累多痛苦……我都會忍住。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"버넷 요원님과 약속했으니까.","JPN":"バーネット様と約束したから。","ENG":"That's what I promised Agent Burnett.","TWN":"因為我跟伯內特先生約好了。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그게 언제까지인데요?","JPN":"それはいつまでですか？","ENG":"And how long does that last?","TWN":"那麼，是到什麼時候？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"응……?","JPN":"え……？","ENG":"Huh...?","TWN":"嗯……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"알고 계셨겠지만, 이곳에서의 시간은 아주 천천히 흐른답니다?","JPN":"わかっていると思いますが、ここでの時間はとてもゆっくり流れますよ。","ENG":"As you are probably aware, time flows extremely slowly here.","TWN":"你應該知道，這裡的時間流逝得很慢吧？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신이 있던 현실에서는 이미 17년이라는 시간이 흘렀죠.","JPN":"あなたが生きていた現実では、すでに17年という歳月が経っています。","ENG":"It has already been 17 years in your original world.","TWN":"在你所在的現實中，已經過去了17年的時間。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그 현실에서의 <color=#ffd34c>1분</color>이 이곳에서는 대략 <color=#ffd34c>1시간</color>정도예요.","JPN":"その現実での<color=#ffd34c>1分</color>がここでは約<color=#ffd34c>1時間</color>にあたります。","ENG":"<color=#ffd34c>1 minute</color> in that world is around <color=#ffd34c>1 hour</color> in this world.","TWN":"現實中的<color=#ffd34c>1分鐘</color>在這裡大概是<color=#ffd34c>1小時</color>左右。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇다면, 17년이라는 시간은 이 세계 기준으로 따지면 어느 정도일지…….","JPN":"つまり、17年という期間はこの世界ではどれぐらいの時間になるか……","ENG":"Then, do you realize...","TWN":"那麼，以這個世界為准，17年的時間又是多長呢……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"가늠이 되시나요?","JPN":"計算できますか？","ENG":"how long 17 years would be in this world?","TWN":"你能猜到嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"我，我……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신의 파수꾼 노릇을 하던 안나 맥크레디는 영생을 추구하던 자였어요.","JPN":"あなたの番人をやっていたアンナ・マクレディーは、不老不死を求めていた者です。","ENG":"Your guard, Anna MacCready, was someone who pursued eternal life.","TWN":"你的守護者安娜·麥克蕾蒂，是一個追求永生的人。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그런, 그녀조차 시간의 무료함을 버티지 못하고 스스로를 동결시켰다가 필요할 때만 움직였죠.","JPN":"そんな彼女さえ、暇を持て余して自分自身を凍結させては必要な時にだけ動いていました。","ENG":"Even she could not withstand the monotony of time and froze herself, only moving when necessary.","TWN":"連她都沒能撐住時間的無聊，把自己凍結起來，只在需要的時候行動。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"당신도 비슷하죠?","JPN":"あなたも同じですよね？","ENG":"Aren't you doing something similar?","TWN":"你也一樣吧？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"능력을 이용하여 과거로, 과거로…….","JPN":"能力を使って、過去へ、過去へ……","ENG":"You're using your abilities to go back, again and again...","TWN":"利用能力回到過去，再回到過去……"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"반복하고 있다는 사실조차 망각한 채, 그날의 꿈에 매달렸잖아요.","JPN":"繰り返しているということすら忘れ、あの日の夢に縋っていたじゃないですか。","ENG":"Clinging on to that dream, forgetting the fact that it was repeating.","TWN":"甚至忘記了不斷的重複，一直沉醉在那天的夢裡。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"시, 싫어……!","JPN":"い、嫌よ……！","ENG":"N-no...!","TWN":"不，不要……！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"좋지도 않은 기억이었을 텐데, 꿈의 반복을 멈출 수 없었던 것은.","JPN":"あまりいい思い出でもなかったでしょうに、それでも夢を繰り返すことを止められなかったのは……","ENG":"It wasn't even a good memory. Yet, you could not stop repeating that dream.","TWN":"明明是不好的記憶，但卻無法停止夢的反復。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"그렇게라도 하지 않으면…… 무척 외로웠을 테니까.","JPN":"そうでもしないと……寂しかったから。","ENG":"Because, if not for that... you would've felt very lonely.","TWN":"因為如果不那麼做……就會很孤獨。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DISTURBER_PRYDWEN_NULL_SHADOW","text":{"KOREA":"다시금 눈을 뜨면 혼자라는 사실을…… 버틸 수 없었을 테니까.","JPN":"目を開けると一人だという事実に……耐えきれなかったから。","ENG":"Because you would not have been able to handle the fact that... you are all alone when you open your eyes.","TWN":"因為再次睜開眼睛時，當發現自己是一個人後……會撐不下去。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"DISTURBER_PRYDWEN_NULL_SHADOW","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"싫다고……!!","JPN":"いや……！！","ENG":"No...!!","TWN":"不要啊……！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};